import type { UmbSubmittableWorkspaceContext } from "@umbraco-cms/backoffice/workspace";
import {
  UmbSubmittableWorkspaceContextBase,
  UmbWorkspaceIsNewRedirectController,
} from "@umbraco-cms/backoffice/workspace";
import type { UmbControllerHostElement } from "@umbraco-cms/backoffice/controller-api";
import { UmbObjectState } from "@umbraco-cms/backoffice/observable-api";
import type { FieldPreValueSource, PreValue } from "@umbraco-forms/generated";
import { UMB_ACTION_EVENT_CONTEXT } from "@umbraco-cms/backoffice/action";
import { UmbRequestReloadChildrenOfEntityEvent, UmbRequestReloadStructureForEntityEvent } from "@umbraco-cms/backoffice/entity-action";
import { FORMS_PREVALUESOURCE_ENTITY_TYPE, FORMS_PREVALUESOURCE_ROOT_ENTITY_TYPE } from "../entities.js";
import { FormsPrevalueSourceDetailRepository } from "../repository/index.js";
import { FormsPrevalueSourceTypeDetailRepository } from "../../provider-types/prevaluesource-types/repository/detail/index.js";
import { PREVALUESOURCE_WORKSPACE_ALIAS } from "./manifests.js";
import FormsWorkspaceEditorElement from "./prevaluesource-workspace-editor.element.js";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";
import { UmbLocalizationController } from "@umbraco-cms/backoffice/localization-api";

export class FormsPrevalueSourceWorkspaceContext
  extends UmbSubmittableWorkspaceContextBase<FieldPreValueSource>
  implements UmbSubmittableWorkspaceContext
{
  public readonly prevalueSourceRepository =
    new FormsPrevalueSourceDetailRepository(this);
  public readonly prevalueSourceTypeRepository =
    new FormsPrevalueSourceTypeDetailRepository(this);

  #data = new UmbObjectState<FieldPreValueSource | undefined>(undefined);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  #getDataPromise?: Promise<any>;

  readonly data = this.#data.asObservable();
  readonly unique = this.#data.asObservablePart((data) => data?.unique);
  readonly name = this.#data.asObservablePart((data) => data?.name);
  readonly id = this.#data.asObservablePart((data) => data?.unique);

  #prevalues = new UmbObjectState<Array<PreValue>>([]);

  readonly prevalues = this.#prevalues.asObservable();

  constructor(host: UmbControllerHostElement) {
    super(host, PREVALUESOURCE_WORKSPACE_ALIAS);

    this.routes.setRoutes([
      {
        path: "create/:type",
        component: FormsWorkspaceEditorElement,
        setup: async (_component, info) => {
          const prevalueSourceType = info.match.params.type;
          await this.create(prevalueSourceType);
        },
      },
      {
        path: "edit/:unique",
        component: FormsWorkspaceEditorElement,
        setup: (_component, info) => {
          const unique = info.match.params.unique;
          this.load(unique);
        },
      },
    ]);
  }

  async load(id: string) {
    this.#getDataPromise = this.prevalueSourceRepository?.requestByUnique(id);
    const { data } = await this.#getDataPromise;

    if (data) {
      this.setIsNew(false);
      this.#data.update(data);
      await this.#refreshPrevalues(data.unique);
    }
  }

  async create(type: string) {
    const scaffold =
      await this.prevalueSourceRepository?.requestPrevalueSourceScaffold();

    let data = scaffold.data!;
    data.fieldPreValueSourceTypeId = type;

    if (this.modalContext) {
      data = { ...data, ...this.modalContext.data.preset };
    }
    this.setIsNew(true);
    this.#data.setValue(data);
    return { data };
  }

  async submit(): Promise<void> {
    if (!this.#data.value) return;
    if (!this.#data.value.unique) return;

    if (this.#data.value.name.trim().length === 0) {
      const notificationContext = await this.getContext(
        UMB_NOTIFICATION_CONTEXT
      );
      const localize = new UmbLocalizationController(this);
      notificationContext.peek("danger", {
        data: { message: localize.term("formEdit_noNameForForm") },
      });
      return;
    }

    const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);

    if (this.getIsNew()) {
      const { error } = await this.prevalueSourceRepository.create(
        this.#data.value,
        null
      );
      if (error) return;

      const event = new UmbRequestReloadChildrenOfEntityEvent({
        entityType: FORMS_PREVALUESOURCE_ROOT_ENTITY_TYPE,
        unique: null,
      });
      eventContext.dispatchEvent(event);
      this.setIsNew(false);
      return;
    }

    const { error } = await this.prevalueSourceRepository.save(
      this.#data.value
    );

    if (error) return;

    await this.#refreshPrevalues(this.#data.value.unique);

    const event = new UmbRequestReloadStructureForEntityEvent({
      unique: this.getUnique(),
      entityType: this.getEntityType(),
    });
    eventContext.dispatchEvent(event);
  }

  async loadPrevalueSourceType(id: string) {
    const { data } = await this.prevalueSourceTypeRepository.requestByUnique(
      id
    );
    return data;
  }

  async #refreshPrevalues(id: string) {
    const { data } = await this.prevalueSourceRepository.requestPrevalues(id);
    if (data) {
      this.#prevalues.update(data);
    }
  }

  getData() {
    return this.#data.getValue();
  }

  getPrevalues() {
    const value = this.#prevalues.getValue();
    return Object.keys(value).map(key => (value[key])); // Transform into an array.
  }

  getUnique() {
    return this.getData()?.unique || "";
  }

  getPrevalueSourceTypeId() {
    return this.getData()?.fieldPreValueSourceTypeId || "";
  }

  getEntityType(): string {
    return FORMS_PREVALUESOURCE_ENTITY_TYPE;
  }

  getName() {
    return this.#data.getValue()?.name;
  }

  setName(name: string) {
    this.#data.update({ name });
  }

  setPrevalueSourceProperty(alias: string, value: any) {
    this.#data.update({ [alias]: value });
  }

  getPrevalueSourceProperty(alias: string) {
    return this.getData()?.[alias];
  }

  destroy() {
    this.#data.destroy();
  }
}

export const api = FormsPrevalueSourceWorkspaceContext;
