import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import {
  LitElement,
  css,
  customElement,
  html,
  property,
  state,
} from "@umbraco-cms/backoffice/external/lit";
import {
  UUIInputEvent
} from "@umbraco-cms/backoffice/external/uui";
import { FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT } from "./prevaluesource-workspace.context-token.js";

const elementName = "forms-prevaluesource-workspace-editor";

@customElement(elementName)
export class FormsPrevalueSourceWorkspaceEditorElement extends UmbElementMixin(LitElement) {
  @state()
  private _prevalueSourceName = "";

	@property({ type: String, attribute: false })
	workspaceAlias?: string;

  #workspaceContext?: typeof FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT.TYPE;

  constructor() {
    super();

    this.consumeContext(FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT, (context) => {
      this.#workspaceContext = context;
			this.#observeId();
		});
	}

	#observeId() {
		if (!this.#workspaceContext) return;
		this.observe(this.#workspaceContext.data, (data) => (this._prevalueSourceName = data?.name ?? ''));
	}

  #onChangeName(e: UUIInputEvent) {
    this.#workspaceContext?.setName(e.target.value.toString());
  }

  render() {
    return html`
      <umb-workspace-editor alias="Forms.Workspace.PrevalueSources">
        <uui-input
          slot="header"
          id="nameInput"
          label=${this.localize.term('placeholders_entername')}
          placeholder=${this.localize.term('placeholders_entername')}
          required
          .value=${this._prevalueSourceName}
          @input="${this.#onChangeName}"
        ></uui-input>
      </umb-workspace-editor>`;
  }

  static styles = [
    css`
        :host {
            display: block;
            width: 100%;
            height: 100%;
        }

        #nameInput {
            flex: 1 1 auto;
        }
    `,
];}

export default FormsPrevalueSourceWorkspaceEditorElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsPrevalueSourceWorkspaceEditorElement;
  }
}
